## 完全背包

```cpp
#include <bits/stdc++.h>

using namespace std;

int n, m, p[1001], v[1001], w[1001];

int main() {
    scanf("%d%d", &n, &m);
    for (int i = 1; i <= n; i++)
        scanf("%d%d", &v[i], &w[i]);
    memset(p, 0, sizeof(p));
    for (int i = 1; i <= n; i++)
        for (int j = v[i]; j <= m; j++)
                p[j] = max(p[j], p[j - v[i]] + w[i]);
    printf("%d\n", p[m]);    
}
```

## 多重背包

```cpp
#include<bits/stdc++.h>
using namespace std;
#pragma GCC optimize(2)
#define please return
#define ac 0
#define fi first
#define se second
#define lowbit(x) x&(-x)
#define endl '\n'
#define pb push_back
#define mkp make_pair
#define all(x0) x0.begin(),x0.end()
#define ll long long
#define ull unsigned long long
#define pdd pair<double,double>
#define pci pair<char,int>
#define pii pair<int,int>
#define IOS ios::sync_with_stdio(0),cin.tie(0),cout.tie(0)
namespace acm{
    typedef int ET;
    ET qpow(ET a,ET b,ET p){
        ET r=1;
        while(b){
            if(b&1){
                r=r*a%p;
            }
            a=a*a%p;
            b>>=1;
        }
        return r%p;
    }
    void debug(ET *a,int n){
        for(int i=1;i<=n;i++){
            cout<<a[i]<<" ";
        }
        cout<<endl;
    }
    ET read(){
        ET f=1,x=0;
        char ss=getchar();
        while(ss<'0'||ss>'9'){if(ss=='-')f=-1;ss=getchar();}
        while(ss>='0'&&ss<='9'){x=x*10+ss-'0';ss=getchar();}
        return f*x;
    }
}
using namespace acm;
int n,m;
int const N = 2e3+5;
int p[N],v[N],w[N],l[N];
void solve(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        cin>>v[i]>>w[i]>>l[i];
    memset(p,0,sizeof p);
    for(int i=1;i<=n;i++){
        int res=l[i];
        for(int k=1;k<=res;res-=k,k*=2){//把每个l[i]分成logl[i]份
            for(int j=m;j>=v[i]*k;j--){
                p[j]=max(p[j],p[j-v[i]*k]+w[i]*k);
            }
        }
        for(int j=m;j>=v[i]*res;j--){//剩下了几份
            p[j]=max(p[j],p[j-v[i]*res]+w[i]*res);
        }
    }
    cout<<p[m]<<endl;
}
int main(){
    IOS;
    int tt=1;
    // cin>>tt;
    while(tt--){
        solve();
    }
    please ac;
}
```

