void up(int i){
    siz[i]=1;
    vis[i]=1;
    for(auto to:g[i]){
        if(!vis[to]){
            up(to);
            siz[i]+=siz[to];
            f[i]+=f[to];
        }
    }
    f[i]+=siz[i]-1;
}
void down(int i){
    vis[i]=1;
    for(auto to:g[i]){
        if(!vis[to]){
            v[to]=v[i]+f[i]-f[to]-siz[to]+n-siz[to];
            down(to);
        }
    }
}
void solve(){
    cin>>n;
    for(int i=1;i<n;i++){
        cin>>x>>y;
        g[x].pb(y);
        g[y].pb(x);
    }
    memset(vis,0,sizeof vis);
    up(1);
    memset(vis,0,sizeof vis);
    down(1);
    for(int i=1;i<=n;i++){
        cout<<f[i]+v[i]<<endl;
    }
