typedef long long ll;
int const N = 25;
double d[N],p,q,sum;
int main(){
	while(scanf("%lf",&p)!=EOF){
		q=1-p;
		d[0]=1/p;
		d[1]=1/p+q/(p*p);
		for(int i=2;i<=20;i++){
			d[i]=1+q*(d[i-2]+d[i-1]);
			d[i]/=p;
		}
