### 思路

题解说不要纠结于当前是第几轮，值得感叹的是我一开始就没想过这事。

[题解](https://blog.csdn.net/moon_sky1999/article/details/98097470?ops_request_misc=&request_id=&biz_id=102&utm_term=Light%20OJ%201408&utm_medium=distribute.pc_search_result.none-task-blog-2~all~sobaiduweb~default-0-98097470.142^v31^down_rank,185^v2^control&spm=1018.2226.3001.4187)

确定状态fi为连续i次成功距离结束的期望

状态gi为连续i次失败距离结束的期望

f[i]=p∗f[i+1]+(1−p)∗g[1]+1

g[i]=(1−p)∗g[i+1]+p∗f[1]+1

令i=1，递推出f1和g1的结果



### Code

```c++
#include<bits/stdc++.h>
using namespace std;
int x,y; 
double p;
double qpow(double a,int b){
	double r=1;
	while(b){
		if(b&1)
			r=r*a;
		a=a*a;
		b>>=1;
	}
	return r;
}
int main(){
	int t;
	scanf("%d",&t);
	int qqq=0;
	while(t--){
		scanf("%lf%d%d",&p,&x,&y);
		p=1-p;
		if(p==0){
			printf("Case %d: %d\n",++qqq,y);
			continue;
		}
		else if(p==1){
			printf("Case %d: %d\n",++qqq,x);
			continue;
		}
		double q=1.0-p;
		double c=1-qpow(q,y-1.0);
		printf("%f\n",c);
		double d=(1-qpow(q,y-1.0))/p;
		double e=(1-qpow(p,x-1.0));
		double f=(1-qpow(p,x-1.0))/q;
		double fx=(d*e+f)/(1-c*e);
		double gx=c*fx+d;
		//printf("%f %f\n",fx,gx);
		printf("Case %d: %.6f\n",++qqq,(p*fx+q*gx+1.0));
	}
	return 0;
}
