### 思路

一般求概率是正推，求期望是逆推。通过题目可以体会到这点。

还是根据状态写方程，化简即可。

概率类问题和操作次数虽然有关但是不可能以操作数列方程，根据状态来才比较好

### Code

记忆化搜索

```cpp
#include <stdio.h>

using namespace std;

// 一个软件有s个子系统，会产生n种bug  某人一天发现一个bug,这个bug属于一个子系统，
// 属于一个分类 每个bug属于某个子系统的概率是1/s,属于某种分类的概率是1/n 问发现n种bug,每个子系统都发现bug的天数的期望。

/*
	一般求概率是正推，求期望是逆推。通过题目可以体会到这点。
	dp[i][j] = 	
*/

int const N = 1e3+5;

int n,s;

double f[N][N];

double dfs(int x,int y){
	if(f[x][y]!=-1)return f[x][y];
	if(x==n&&y==s)return 0;
	double ans=0;
	ans=(dfs(x+1,y+1)*(n-x)*(s-y)+dfs(x+1,y)*((n-x)*y)+dfs(x,y+1)*(x*(s-y))+1.0*n*s)/(1.0*n*s-x*y);
	return f[x][y]=ans;
}

int main(){
	while(~scanf("%d%d",&n,&s)){
		for(int i=0;i<=n;i++){
			for(int j=0;j<=s;j++){
				f[i][j]=-1;
			}
		}
		printf("%.4f\n",dfs(0,0));
	}
	return 0;
}
```



## ZOJ 3329

[ZOJ (pintia.cn)](https://zoj.pintia.cn/problem-sets/91827364500/problems/91827368253)

成环的概率

### 思路

首先是找好状态

三个筛子的结果多样而且不同结果有不同的分数，并且最后的胜利以分数论，所以状态应该选用分数

dpi=当前分数为i时所需期望

dpi= r dp0 + 求和 px \* dpx+i +1

当 x+i >=n dpx+i=0

r=1/(k1\*k2\*k3)

出现了dp0，有环



用换元的思想

把dp0看成常数，

dpi=Ai \* dp0 + Bi



带入

dpi=(求和pk\*A[i+k]+p0)dp[0]+求和pk\*B[i+k]+1

Ai=(求和pk\*A[i+k]+p0)

Bi=(求和pk\*B[i+k])



dp0 = B[0] /(1-A[0])



### Code

```cpp
#include <stdio.h>
#include <string.h>
using namespace std;

int const N = 5e2+40;
int n,k1,k2,k3,a,b,c;
double p[N];
double A[N],B[N];

int main(){
	int t;
	scanf("%d",&t);
	while(t--){

		scanf("%d%d%d%d%d%d%d",&n,&k1,&k2,&k3,&a,&b,&c);
		memset(p,0,sizeof p);
		memset(A,0,sizeof A);
		memset(B,0,sizeof B);
		p[0]=(1.0/k1/k2/k3);
		for(int i=1;i<=k1;i++){
			for(int j=1;j<=k2;j++){
				for(int k=1;k<=k3;k++){
					if(!(i==a&&j==b&&k==c)){
						p[i+j+k]+=p[0];
					}
				}
			}
		}
		for(int i=n;i>=0;i--){
			A[i]=p[0];
			B[i]=1;
			for(int j=3;j<=k1+k2+k3;j++){
				if(i+j>n)continue;
				A[i]+=A[i+j]*p[j];
				B[i]+=B[i+j]*p[j];
			}
		}
		printf("%.10f\n",B[0]/(1-A[0]));
	}
	return 0;
}
```



