	if(cnt>k)return 0;
	else if(cnt==k){
		for(int i=0;i<n;i++){
			if(x&(1<<i))ans[i]+=dp[x];
		}
		return dp[x];
	}
	else{
		for(int i=0;i<n;i++){
			if(!(x&(1<<i))){
				int t=(1<<i)|x;
				dp[t]+=dp[x]*(p[i]/qqq);
			}
		}
		return dp[x];
	}
}

int main(){
	scanf("%d%d",&n,&k);
	int m=n;
	for(int i=0;i<n;i++){
		//scanf("%lf",&p[i]);
		scanf("%Lf",&p[i]);
		//cin>>p[i];
		if(p[i]<=1e-10)m--;
	}
	k=min(m,k);
	dp[0]=1;
	for(int i=0;i<=(1<<n)-1;i++){
		dp[i]=dfs(i);
	}
	for(int i=0;i<n;i++){
		printf("%.9Lf ",ans[i]);
	}printf("\n");
	return 0;
}
