# 维护区间信息

https://leetcode.cn/problems/subarray-product-less-than-k/

```c++
class Solution {
public:
    int numSubarrayProductLessThanK(vector<int>& nums, int k) {
        int n=nums.size();
        long long now=1;
        int ans=0;
        int l=0;
        for(int r=0;r<n;r++){//不断移动右指针
            now*=nums[r];//更新维护值
            while(l<=r&&now>=k){//不满足条件则移动左指针
                now/=nums[l];
                l++;
            }
            ans+=(r-l+1);//更新答案
        }
        return ans;
    }
};
```

