class Solution {
public:
    string findLongestWord(string s, vector<string>& dictionary) {
        string ans="";
        int len=0;
        sort(dictionary.begin(),dictionary.end());
        for(int i=dictionary.size()-1;i>=0;i--){
            string t=dictionary[i];
            int r=0;
            for(int l=0;l<s.size();l++){
                if(s[l]==t[r])r++;//如果能匹配两者一起移动
            }
            if(r==t.size()){
                if(t.size()>=len){
                    len=t.size();
                    ans=t;
                }
            }
        }
        return ans;
    }
};
