https://leetcode.cn/problems/two-sum-ii-input-array-is-sorted/

```c++
class Solution {
public:
    vector<int> twoSum(vector<int>& numbers, int target) {
        int l=0,r=numbers.size()-1;
        int now=numbers[l]+numbers[r];
        vector<int> ans;
        while(l<=r){
            if(now<target){
                now=now-numbers[l]+numbers[l+1];
                l++;
            }
            else if(now>target){
                now=now-numbers[r]+numbers[r-1];
                r--;
            }
            else{
                ans.push_back(l+1);
                ans.push_back(r+1);
                break;
            }
        }
        return ans;
    }
};
```

