```cpp
#include<bits/stdc++.h>
using namespace std;
int const N = 2e3+10;
int const mod = 998244353;
long long n,k;
long long x[N],y[N];
long long qpow(long long a,long long b){
    long long r=1;
    while(b){
        if(b&1){
            r=r*a%mod;
        }
        a=a*a%mod;
        b>>=1;
    }
    return r%mod;
}
int main(){
    scanf("%lld%lld",&n,&k);
    for(int i=1;i<=n;i++){
        scanf("%lld %lld",&x[i],&y[i]);
    }
    long long ans=0;
    for(int i=1;i<=n;i++){
        long long cnt=y[i];
        for(int j=1;j<=n;j++){
            if(i==j)continue;
            cnt=(cnt*(k-x[j])%mod)*qpow(x[i]-x[j],mod-2)%mod;
        }
        ans=(ans+cnt)%mod;
    }
    printf("%lld\n",(ans+mod)%mod);
    return 0;
}
