```c++
#include <cstdio>
#include <algorithm>
#include <cstring>
using namespace std;
const int maxn = 1e6 + 5;

int  n, q;
int a[maxn];
int sum[maxn];
long long BIT[maxn], BIT2[maxn];

int Lowbit(int a){
	return a & (-a);
}

void Update(int x, int k){
	for(int i = k; i <= n; i += Lowbit(i)){
		BIT[i] += x;
	}
}

void Update2(int x, int k){
	for(int i = k; i <= n; i += Lowbit(i)){
		BIT2[i] += (long long)x * (k - 1);
	}
}

long long Sum(int x){
	long long ans = 0;
	for(int i = x; i > 0; i -= Lowbit(i)){
		ans += BIT[i];
	}
	return ans;
}

long long Sum2(int x){
	long long ans = 0;
	for(int i = x; i > 0; i -= Lowbit(i)){
		ans += BIT2[i];
	}
	return ans;
}

int main() {
	scanf("%d %d", &n, &q);
	for(int i = 1; i <= n; i ++){
		scanf("%d", &a[i]);
		sum[i] = a[i] - a[i - 1];
		Update(sum[i], i);
		Update2(sum[i], i);
	}
	for(int i = 1; i <= q; i ++){
		int flag;
		scanf("%d", &flag);
		if(flag == 1){
			int x, l, r;
			scanf("%d %d %d", &l, &r, &x);
			Update(x, l);
			Update(-x, r + 1);
			Update2(x, l);
			Update2(-x, r + 1);
		}
		else{
			int l, r;
			scanf("%d %d", &l, &r);
			printf("%lld\n", (r * Sum(r) - Sum2(r)) - ((l - 1) * Sum(l - 1) - Sum2(l - 1))); 
		} 
	}
	return 0;
} 
