bool bfs(){
	memset(d,0,sizeof d);
	while(q.size())q.pop();
	q.push(s);
	d[s]=1;
	now[s]=head[s];
	while(q.size()){
		int x=q.front();q.pop();
		for(int i=head[x];i;i=Next[i]){
			if(edge[i]&&!d[ver[i]]){
				q.push(ver[i]);
				now[ver[i]]=head[ver[i]];
				d[ver[i]]=d[x]+1;
				if(ver[i]==t)return 1;
			}
		}
	}
	return 0;
}

int dinic(int x,int flow){
	if(x==t)return flow;
	int rest = flow ,k ,i;
	for(i=now[x];i&&rest;i=Next[i]){
		if(edge[i]&&d[ver[i]]==d[x]+1){
			k=dinic(ver[i],min(rest,edge[i]));
			if(!k) d[ver[i]] = 0;
			edge[i] -=k;
			edge[i^1] += k;
			rest -= k;
		}
	}
	now[x]=i;
	return flow-rest;
}

