int find(int x)
{
    return f[x]==x?f[x]:f[x]=find(f[x]);
}
inline void add_edge(int from,int to)
{
    edge[++num].nxt=head[from];
    edge[num].to=to;
    head[from]=num;
}
inline void add(int from,int to)
{
    add_edge(from,to);
    add_edge(to,from);
}
inline int lca(int x,int y)//朴素找lca，虽然笔者自己是死记硬背的。。貌似只会树剖找lca。。
{
    t++;
    while(1){
        if(x){
            x=find(x);//点要对应到相应的花上。
            if(vis[x]==t) return x;
            vis[x]=t;
            if(match[x]) x=next[match[x]];
            else x=0;
        }
        swap(x,y);
    }
}
inline void flower(int a,int p)
{
    while(a!=p){
        int b=match[a],c=next[b];
        if(find(c)!=p) next[c]=b;
        //next数组是用来标记花中的路径，结合match就实现了双向链表的功能。
        //我们可以知道一个奇环里的所有点只要向外面连边就有可能与外面匹配，所以所有奇环中的点都         
　　　　　　要变成S型点扔到队列中。又因为环内部肯定是匹配饱和的，所以这一堆点最多只能匹配出来一             
　　　　　　个点，所以每次匹配到一个点就可以跳出循环了。
        if(mark[b]==2) q.push(b),mark[b]=1;
        if(mark[c]==2) q.push(c),mark[c]=1;
        f[find(a)]=find(b);f[find(b)]=find(c);
        a=c;
    }
}
inline void work(int s)
{
    for(re int i=1;i<=n;i++)
        next[i]=mark[i]=vis[i]=0,f[i]=i;//每个阶段都需要重新标记
    while(!q.empty()) q.pop();
    mark[s]=1;q.push(s);
    while(!q.empty()){
        if(match[s]) return;
        int x=q.front();q.pop();//队列中的点均为S型
        for(re int i=head[x];i;i=edge[i].nxt){
            int y=edge[i].to;
            if(match[x]==y) continue;//x与y是配偶，忽略掉
            if(find(x)==find(y)) continue;//x与y在一朵花里，忽略掉
            if(mark[y]==2) continue;//y是T形点，忽略掉。
            if(mark[y]==1) {//y是s型点，需要缩点
                int r=lca(x,y);
                if(find(x)!=r) next[x]=y;//x和r不在同一个花朵， next标记花朵内的路径
                if(find(y)!=r) next[y]=x;//同上
                flower(x,r);flower(y,r);//将r--x--y--r缩成一个点
            }
            else if(!match[y]){//y没有匹配过，可以增广
                next[y]=x;
                for(re int u=y;u;){//增广操作
                    int v=next[u],w=match[v];
                    match[v]=u;match[u]=v;u=w;
                }
                break;
            } else {//y点已经匹配过，将其配偶作为S型点拉进来，y点本身为T型点，继续搜索。
                next[y]=x;
                mark[match[y]]=1;
                q.push(match[y]);
                mark[y]=2;
            }
        }
    }
}
