    memset(f, 128, sizeof(f));
    f[0][0] = 0;
    for (int i = 1; i <= n; i++)
        for (int j = 0; j <= m; j++)
            if (j < v[i])
                f[i][j] = f[i - 1][j];
            else
                f[i][j] = max(f[i - 1][j], f[i][j - v[i]] + w[i]);
    int ans = 0;
    for (int i = 0; i <= m; i++)
        ans = max(ans, f[n][i]);
    printf("%d\n", ans);
}

