```c++
#include<iostream>
#include<queue>
#include<map>
using namespace std;
struct node
{
    int val;
    int step;
};
int n,k;
map<int,bool> f,used;
queue<node> q;
int main()
{
    cin>>n>>k;
    for(int i=1,u;i<=k;i++)
    {
        cin>>u;
        u-=n;
        if(used[u]==0)
            used[u]=1;
        if(f[u]==0)
            f[u]=1;
    }
    int tot=0;
    for(map<int,bool>::iterator it=used.begin();it!=used.end();it++)
        q.push((node){(*it).first,(*it).second});
    while(!q.empty())
    {
        node t=q.front();
        q.pop();
        if(t.val==0)
        {
            cout<<t.step;
            return 0;
        }
        for(map<int,bool>::iterator it=used.begin();it!=used.end();it++)
        {
            if(f[(*it).first+t.val]==0&&-1000<=(*it).first+t.val&&(*it).first+t.val<=1000)//不断混合搜索
            {
                f[(*it).first+t.val]=1;
                q.push((node){(*it).first+t.val,t.step+1});//所需次数+1
            }
        }
    }
