# H Jury Compromise

把每个人看成容量，相当于把n个物体放到容量为m的背包，而且每个人的体积是1。d-p（控辩差）相当于每个物体的费用。

dp[i] [j] : 选i个人 控辩差为j的方案中最大控辩和的方案

记 sub[i]= d[i]-p[i] ; add[i]=d[i]+p[i];

状态转移方程：dp[i+1] [j+sub[k]]=max(dp[i+1] [j+sub[k] ], dp[i] [ [j]+add[k])

其实就是选i+1个人，辩控差为j+sub[k]的最优方案是由所有能够通过选i个人，辩控差为j再加上一个人k的贡献达到这个状态的辩控和最大的那个方案。

因为这个费用可能为负，所以我们要考虑把[-400,400]映射到[0,800],相当于加了一个修正值fix=20*m.


同时在dp过程中记录路径

最后遍历一次找到答案

```c++

#include<iostream>
#include<algorithm>
#include<cmath>
#include<cstring>
#include<cstdio>
#include<cstdlib>
#include<vector>
using namespace std;
#define pb push_back
int n,m;
int sub[205],add[205],d[205],p[205];
int dp[25][805];
vector<int> path[25][805];
void init(){

    for(int i=0;i<m;i++)
    	for(int j=0;j<802;j++)
    		path[i][j].clear();
    memset(dp,-1,sizeof dp);
}
int main(){
    int kcase=0;
    while(~scanf("%d%d",&n,&m)&&n&&m){
        for(int i=0;i<n;i++){
            scanf("%d %d",&d[i],&p[i]);
            sub[i]=d[i]-p[i];
            add[i]=d[i]+p[i];
        }
        init();
        int fix=m*20;
        dp[0][fix]=0;
        for(int k =0;k<n;k++){
            for(int i=m-1;i>=0;i--){
                for(int j=0;j<=2*fix-1;j++){
                    if(dp[i][j]>=0){
                        if(dp[i+1][j+sub[k]]<=dp[i][j]+add[k]){
                            dp[i+1][j+sub[k]]=dp[i][j]+add[k];
                            path[i+1][j+sub[k]]=path[i][j];
                            path[i+1][j+sub[k]].pb(k);
                        }
                    }
                }
            }
        }
        int i;
        for(i=0;dp[m][fix+i]==-1&&dp[m][fix-i]==-1;i++);

        int temp=dp[m][fix+i]>dp[m][fix-i]?i:-i;//记录最优解的状态，同时保证d+p的和最大
        printf("Jury #%d\n",++kcase);
        int sumD=0,sumP=0;
        for(i=0;i<m;i++){
            sumD+=d[path[m][fix+temp][i]];
            sumP+=p[path[m][fix+temp][i]];
        }
        printf("Best jury has value %d for prosecution and value %d for defence:\n",sumD,sumP);
        for(i=0;i<m;i++) printf(" %d",path[m][fix+temp][i]+1);
        printf("\n\n");
    }
    return 0;
}
```

