int b[maxn][2*maxn];
bool dfs(int i,int t,vector<int> *b){
    team[i]=t;
    b[t].push_back(i);
    bool ok=true;
    for(int j=1;j<=n;j++){
        if(unknow[i][j]){
            if(team[j]==-1) {
                if(!dfs(j,!t,b)){
                    ok=false;
                    break;
                }
            }
            else if(team[j]!=t) continue;
            else{
                ok=false;
                break;
            }
        }
    }
    return ok;
}
bool blocks(){
    for(int i=0;i<maxn;i++)
        for(int j=0;j<2;j++)
            block[i][j].clear();
    num=0;
    for(int i=1;i<=n;i++)
        if(team[i]==-1)
            if(!dfs(i,0,block[num++]))
                return false;
    return true;
}
void dp(){
    memset(d, 0, sizeof d);
    memset(b,0,sizeof b);
    for(int i=0;i<=num;i++){
        for(int j=0;j<2*maxn;j++){
            if(i==0){
                d[i][j]=INF;
                if(j==maxn)
                d[i][j]=0;
                continue;
