            for(int k=0;k<block[i-1][1].size();k++)
                team[1].push_back(block[i-1][1][k]);
            j-=dt;
        }
        else{
            for(int k=0;k<block[i-1][0].size();k++)
                team[1].push_back(block[i-1][0][k]);
            for(int k=0;k<block[i-1][1].size();k++)
                team[0].push_back(block[i-1][1][k]);
            j+=dt;
        }
    }
    printf("%d",int(team[0].size()));
    for(int i=0;i<team[0].size();i++){
        printf(" %d",team[0][i]);
    }
    printf("\n");
    printf("%d",int(team[1].size()));
    for(int i=0;i<team[1].size();i++){
