# 不要求字典序 

先用一个数组储存1-n。

每次把一个数（1- n）放到最左边，然后把剩下的数在缩小了一个规模的情况下继续排列递归。在这样的处理中，0 - l 是我们已经处理好的数据，l+1-r是我们备选的数据。同时这样的处理也会保证每个数只会用一次。

换句话说

事实上维护了一个不断增加的数组，每次都在数组后添加一个数。

```c++
#include<bits/stdc++.h>
using namespace std;
#define MAXN 9

void Swap(int L[],int i,int j){
	int Tmp=L[i];
	L[i]=L[j];
	L[j]=Tmp;
}

void dfs(int L[],int l,int r){//递归处理l-r的全排列
	int i;
	if(l==r){//把i和最左边的数交换
		for(i=0;i<=r;i++)printf("%d",L[i]);
			printf("\n");
	}
	else{
		for(i=l;i<=r;i++){
            //选在当前位置用i的分支
			Swap(L,l,i);
			dfs(L,l+1,r);
            //不选用i
			Swap(L,l,i);//复原
		}
	}
}

int main(){
	int n,L[MAXN];
	scanf("%d",&n);
	for(int i=0;i<n;i++)L[i]=i+1;
		dfs(L,0,n-1);
	return 0;
}
