## 判断法则
如果不是根节点：
```cpp
dfn[x]<=low[y]
```
如果是根节点
至少有两个满足上述式子

## 注意
因为式子是= 所以无需考虑父节点和重边等问题
只要能到达结点就可以用来更新low

## code
其中cur表示是否是割点

```cpp
#include<cstdio>
#include<cstring>
#define min(a,b) a<b?a:b
int const maxn = 100010;
struct EDGE
{
	int to,next;
}edge[maxn<<1];

int head[maxn],low[maxn],dfn[maxn];
int n,m,tot,num;
int root;
bool cur[maxn];

void add(int u,int v){
	edge[++tot].to=v;
	edge[tot].next=head[u];
	head[u]=tot;
}

void tarjan(int x){
	dfn[x]=low[x]=++num;
	int flag=0;
	for(int i=head[x];i;i=edge[i].next){
		int y=edge[i].to;
		if(!dfn[y]){
			tarjan(y);
			low[x]=min(low[x],low[y]);
			if(low[y]>=dfn[x]){
				flag++;
				if(x!=root||flag>1){
					cur[x]=1;
				}
			}
		}
		else low[x]=min(low[x],dfn[y]);
	}
}
int main(){
	for(int i=1;i<=n;i++){
        if(!dfn[i]){
            root=i;
            tarjan(i);
        }
    }
	return 0;
}
