# 强连通分量
如果有low[x]==dfn[x]成立，则从x到栈顶的所有结点构成一个强连通分量

```cpp
#include<bits/stdc++.h>
using namespace std;
int const maxn = 100010;
int const maxm = 1000010;

struct EDGE
{
	int to,next;
}edge[maxm];

int head[maxn],low[maxn],dfn[maxn];
int stac[maxn],ins[maxn],c[maxn];
vector<int>scc[maxn];
int n,m,tot,num,top,cnt;

int vc[maxn],nc[maxn],hc[maxn],tc;
void add_c(int x,int y){
	vc[++tc]=y;
	nc[tc]=hc[x];
	hc[x]=tc;
}

void add(int x,int y){
	edge[++tot].to=y;
	edge[tot].next=head[x];
	head[x]=tot;
}

void tarjan(int x){
	dfn[x]=low[x]=++num;
	stac[++top]=x,ins[x]=1;
	for(int i=head[x];i;i=edge[i].next){
		int j=edge[i].to;
		if(!dfn[j]){
			tarjan(j);
			low[x]=min(low[x],low[j]);
		}
		else if(ins[j]){
			low[x]=min(low[x],dfn[j]);
		}
	}
	if(dfn[x]==low[x]){
		cnt++;
		int y;
		do{
			y=stac[top--];
			ins[y]=0;
			c[y]=cnt;
			scc[cnt].push_back(y);
		}while(x!=y);
	}
}

int main(){
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		int x,y;
		cin>>x>>y;
		add(x,y);
	}
	for(int i=1;i<=n;i++){
		if(!dfn[i])tarjan(i);
	}

	for(int x=1;x<=n;x++){
		for(int i=head[x];i;i=edge[i].next){
			int y=edge[i].to;
			if(c[x]==c[y])continue;
			add_c(c[x],c[y]);
		}
	}

	return 0;
}
