### 树上博弈
叶子的sg为0
#### 克朗原理
对于某个点，sg[u]=(所有子节点的sg+1)的异或和
#### 费森原理
奇数环等价于只有一个端点的一条边
偶数环等价于一个点

#### eg
poj 3780

可以看到，多了一步判断自环（环为2 ）
偶环就一路打上标记
奇环就回去洗白一个


```cpp
#include<cstdio>
#include<cstring>
#define min(a,b) (a<b ? a:b)

int cnt,n,m,k,x,y,top,sg,tot;
int head[105],dfn[105],low[105],sta[105],kk[105][105];
bool vis[105],in[105];

struct Node{
    int nex,to;
}e[1005];

inline void add(int a,int b){
    ++cnt;
    e[cnt].nex = head[a];
    e[cnt].to = b;
    head[a] = cnt;
}

void init(){
    cnt = tot = top = 0;
    memset(dfn,0,sizeof(dfn));
    memset(vis,0,sizeof(vis));
    memset(head,0,sizeof(head));
    memset(kk,0,sizeof(kk));
}

void tarjan(int u,int f){
    sta[++top] = u, in[u] = 1;
    low[u] = dfn[u] = ++tot;
    for(int i = head[u]; i; i = e[i].nex){
        int to = e[i].to;
        if(to == f && kk[to][u]>1){
            if(kk[to][u]%2 == 0)    vis[u] = 1;   
            continue;
        }

        if(!dfn[to]){
            tarjan(to,u);
            low[u] = min(low[u],low[to]);
        }
        else if(to != f && in[to])  low[u] = min(low[u],dfn[to]);
    }
    if(dfn[u] == low[u]){
        int num = 1;
        while(sta[top] != u){
            ++num, in[sta[top]] = 0;
            vis[sta[top--]] = 1;
        }
        --top, in[u] = 0;
        if((num&1) && num > 1)   vis[sta[top+2]] = 0;
    }
}

int get_sg(int u,int f){
    int sg = 0;
    for(int i = head[u]; i; i = e[i].nex){
        int to = e[i].to;
        if(to != f && !vis[to])  sg ^= (get_sg(to,u)+1);
    }
    return sg;
}

int main(){
    while(scanf("%d",&n) != EOF){
        sg = 0;
        while(n--){
            scanf("%d%d",&m,&k);  init();
            for(int i = 1; i <= k; ++i){
                scanf("%d%d",&x,&y);
                add(x,y), add(y,x);
                ++kk[x][y], ++kk[y][x];
            }
            tarjan(1,-1);
            sg ^= get_sg(1,-1);
        }
        if(sg)  puts("Sally");
        else    puts("Harry");        
    }
    return 0;
}
```

