using namespace std;

int const maxn = 20;
int const INF = 0x3f3f3f3f;

int pre[maxn];
bool vis[maxn];
int mp[maxn][maxn];

int s,e;
int n,m;

bool bfs(){
	queue<int>q;
	memset(pre,0,sizeof pre);
	memset(vis,0,sizeof vis);
	vis[s]=1;
	q.push(s);
	while(!q.empty()){
		int first=q.front();
		q.pop();
		if(first==e)return true;

		for(int i=1;i<=n;i++){
			if(!vis[i]&&mp[first][i]){
				q.push(i);
				pre[i]=first;
				vis[i]=1;
			}
		}
	}
	return false;
}

int max_flow(){
	int ans=0;
	while(1){
		if(!bfs())return ans;
		int Min=INF;
		for(int i=e;i!=s;i=pre[i])
			Min=min(Min,mp[pre[i]][i]);
		for(int i=e;i!=s;i=pre[i]){
			mp[pre[i]][i]-=Min;
			mp[i][pre[i]]+=Min;
		}
		ans+=Min;
	}
}

int main(){
	int T;
	scanf("%d",&T);
	int u,v,c;
	for(int cas=1;cas<=T;cas++){
		scanf("%d%d",&n,&m);
