# KM

## 求最大值

```cpp
#include<cstdio>
#include<cstring>
#include<algorithm>
#include<iostream>

using namespace std;

const int MAXN = 305;
const int INF = 0x3f3f3f3f;

int graph[MAXN][MAXN];//记录二分图
int ex_l[MAXN],ex_r[MAXN];//记录L集合对各个R集合元素的期望值。与其相反
bool vis_l[MAXN],vis_r[MAXN];//记录每轮可以成功的配对
int match[MAXN];//记录L集合配对到的R集合对象
int slack[MAXN];//L集合如果可以匹配还需多少

int n;

bool dfs(int r){
	vis_r[r]=true;

	for(int i=1;i<=n;i++){

		if(vis_l[i]) continue;//每一轮，L只匹配一次

		int gap= ex_l[i]+ex_r[r]-graph[r][i]; //双方的期望值和现实的差距

		if(gap==0){//符合了
			vis_l[i] = true ;
			if(match[i]==-1||dfs(match[i])){
				match[i]=r;
				return true;
			}
		}
		else{
			slack[i]=min(slack[i],gap);//还要多少才能匹配
		}
	}
	return false;
}

int KM(){
	memset(match,-1,sizeof match);
	memset(ex_l,0,sizeof ex_l);


		//初始起始期望值是各位的值
	for (int i = 1; i <=n; ++i) {
        ex_r[i] = graph[i][1];
        for (int j = 2; j <= n; ++j) {
            ex_r[i] = max(ex_r[i], graph[i][j]);
        }
    }


	for(int i=1;i<=n;i++){
		fill(slack+1,slack+n+1,INF);//初始为无穷大

		while(1){
			//把r的匹配：如果找不到就降低

			//记录每轮匹配是否被匹配过
			memset(vis_l,false,sizeof vis_l);
			memset(vis_r,false,sizeof vis_r);

			if(dfs(i))break;//找到了就推出

			//如果找不到就降低
			int d=INF;
			for(int j=1;j<=n;j++)
				if(!vis_l[j])d=min(d,slack[j]);

				for(int j=1;j<=n;j++){
					//所有访问过的R降低期望
					//访问过的L增加期望
					//没访问过的L因为R期望降低而可能值增加
					if(vis_r[j])ex_r[j]-=d;
					if(vis_l[j])ex_l[j]+=d;
					else slack[j]-=d;

			}
		}
	}
		int res=0;
		//匹配完成
		for(int i=1;i<=n;i++){
			res+=graph[match[i]][i];
		}


	return res;
}
int main()
{
    while (~scanf("%d", &n)) {

        for (int i = 1; i <=n; ++i)
            for (int j = 1; j <=n; ++j)
                scanf("%d", &graph[i][j]);

        printf("%d\n", KM());
    }
    return 0;
}
```

## 求最小值

把边权取负

```cpp
#include <iostream>
#include <cstring>
#include <cstdio>
#include <cmath>
#include <cstdlib>
#include <vector>
using namespace std;
const int MAXN = 205;
const int INF = 0x3f3f3f3f;
#define PII pair<int,int>
int love[MAXN][MAXN];   // 记录每个妹子和每个男生的好感度
int ex_girl[MAXN];      // 每个妹子的期望值
int ex_boy[MAXN];       // 每个男生的期望值
bool vis_girl[MAXN];    // 记录每一轮匹配匹配过的女生
bool vis_boy[MAXN];     // 记录每一轮匹配匹配过的男生
int match[MAXN];        // 记录每个男生匹配到的妹子 如果没有则为-1
int slack[MAXN];        // 记录每个汉子如果能被妹子倾心最少还需要多少期望值
char mp[MAXN][MAXN];
int N;
vector<PII> id_girl,id_boy;

bool dfs(int girl)
{
    vis_girl[girl] = true;

    for (int boy = 0; boy < N; ++boy) {

        if (vis_boy[boy]) continue; // 每一轮匹配 每个男生只尝试一次

        int gap = ex_girl[girl] + ex_boy[boy] - love[girl][boy];

        if (gap == 0) {  // 如果符合要求
            vis_boy[boy] = true;
            if (match[boy] == -1 || dfs( match[boy] )) {    // 找到一个没有匹配的男生 或者该男生的妹子可以找到其他人
                match[boy] = girl;
                return true;
            }
        } else {
            slack[boy] = min(slack[boy], gap);  // slack 可以理解为该男生要得到女生的倾心 还需多少期望值 取最小值 备胎的样子
        }
    }

    return false;
}

int KM()
{
    memset(match, -1, sizeof match);    // 初始每个男生都没有匹配的女生
    memset(ex_boy, 0, sizeof ex_boy);   // 初始每个男生的期望值为0

    // 每个女生的初始期望值是与她相连的男生最大的好感度
    for (int i = 0; i < N; ++i) {
        ex_girl[i] = love[i][0];
        for (int j = 1; j < N; ++j) {
            ex_girl[i] = max(ex_girl[i], love[i][j]);
        }
    }


    // 尝试为每一个女生解决归宿问题
    for (int i = 0; i < N; ++i) {

        fill(slack, slack + N, INF);    // 因为要取最小值 初始化为无穷大

        while (1) {
            // 为每个女生解决归宿问题的方法是 ：如果找不到就降低期望值，直到找到为止

            // 记录每轮匹配中男生女生是否被尝试匹配过
            memset(vis_girl, false, sizeof vis_girl);
            memset(vis_boy, false, sizeof vis_boy);

            if (dfs(i)) break;  // 找到归宿 退出

            // 如果不能找到 就降低期望值
            // 最小可降低的期望值
            int d = INF;
            for (int j = 0; j < N; ++j)
                if (!vis_boy[j]) d = min(d, slack[j]);

            for (int j = 0; j < N; ++j) {
                // 所有访问过的女生降低期望值
                if (vis_girl[j]) ex_girl[j] -= d;

                // 所有访问过的男生增加期望值
                if (vis_boy[j]) ex_boy[j] += d;
                // 没有访问过的boy 因为girl们的期望值降低，距离得到女生倾心又进了一步！
                else slack[j] -= d;
            }
        }
    }

    // 匹配完成 求出所有配对的好感度的和
    int res = 0;
    for (int i = 0; i < N; ++i)
        res += love[ match[i] ][i];

    return -res;
}

int main()
{
    int n,m;
    while(scanf("%d%d%*c",&n,&m)&&n+m){
        id_girl.clear();
        id_boy.clear();
        for(int i=0;i<n;i++){
            scanf("%s",mp[i]);
        }



        for(int i=0;i<n;i++){
            for(int j=0;j<m;j++){
                if(mp[i][j]=='m')id_boy.push_back(make_pair(i,j));
                if(mp[i][j]=='H')id_girl.push_back(make_pair(i,j));
            }
        }


    for(int i=0;i<id_boy.size();i++){

        for(int j=0;j<id_girl.size();j++){
            int dis=abs(id_boy[i].first - id_girl[j].first) + abs(id_boy[i].second - id_girl[j].second);
            love[i][j]=-dis;   //取负 

        }
    } 
    N=id_boy.size();


    printf("%d\n", KM());
}
    return 0;
}

