# prim
在保证连通的情况下取最短边
（选点）
如果用链式前向星写就发现很省力
## 链式前向星
```cpp
#include<bits/stdc++.h>
using namespace std;

const int N=5010;
const int M=4*1e5+10;
const int INF= 1e9+7;

int tot,n,m;
int head[N],dis[N];
bool vis[N];

struct EDGE
{
	int to,w,nex;
}edge[M];

void init(){
	tot=0;
	fill(head,head+n+1,-1);
	memset(vis,false,sizeof vis);
}

void init_dis(){
	for(int i=1;i<=n;i++)
		dis[i]=INF;
}

void add_edge(int u,int v,int val){
	edge[++tot].to=v;
	edge[tot].w=val;
	edge[tot].nex=head[u];
	head[u]=tot;
}

int prim(int s){
	init_dis();
	dis[s]=0;

	for(int i=head[s];i!=-1;i=edge[i].nex){
		int v=edge[i].to;
		dis[v]=min(dis[v],edge[i].w);
	}

	int cnt=0,ans=0;
	vis[s]=true;
	int k;
	while(++cnt<n){
		int mmin=INF;
		k=-1;
		for(int i=1;i<=n;i++){
			if(!vis[i]&&mmin>dis[i]){
				k=i;
				mmin=dis[i];
			}
		}

		if(k==-1)break;
		vis[k]=true;
		ans+=mmin;

		for(int i=head[k];i!=-1;i=edge[i].nex){
			int v=edge[i].to;
			if(!vis[v]&&dis[v]>edge[i].w)dis[v]=edge[i].w;
		}
	}
	if(k==-1)return -1;
	else return ans;
}

int main(){
	scanf("%d%d",&n,&m);
	init();
	for(int i=1;i<=m;i++){
		int a,b,c;
		scanf("%d%d%d",&a,&b,&c);
		add_edge(a,b,c);
		add_edge(b,a,c);
	}
	int f=prim(1);
	if(f==-1)printf("orz\n");
	else printf("%d\n",f);
	return 0;
}
