		for(int i=1;i<=n;i++){
			if(!vis[i]&&mmin>dis[i]){
				k=i;
				mmin=dis[i];
			}
		}

		if(k==-1)break;
		vis[k]=true;
		ans+=mmin;

		for(int i=1;i<=n;i++){
