# kruskal
在无回路的情况下选最短边


```cpp
#include<bits/stdc++.h>
using namespace std;
const int ms=2e5+9;
#define inf 1000000000
int n,m;
int fa[ms];
struct node{
	int u,v,w;
}edge[ms];

int find(int x)
{
	return fa[x]==x?x:fa[x]=find(fa[x]);
}

bool cmp(node x,node y)
{
	return x.w<y.w;
}

int kruskal()
{
	int ans=0,cnt=0;
	sort(edge+1,edge+1+m,cmp);
	for(int i=1; i<=m; i++)
	{
		int fu=find(edge[i].u);
		int fv=find(edge[i].v);
		if(fu==fv) continue;
		fa[fv]=fu;
		ans+=edge[i].w;
		if(++cnt==n-1) break;
	}
    if(cnt==n-1) printf("%d\n",ans);
    else printf("orz\n");
}

int main()
{

	scanf("%d %d",&n,&m);
	for(int i=1; i<=n; i++) fa[i]=i; 
	for(int i=1; i<=m; i++)
		scanf("%d %d %d",&edge[i].u,&edge[i].v,&edge[i].w);
	kruskal();
	return 0;
}
