初始化的low和dfn应当一样
如果遍历到 没有遍历过的点，以这个点开始dfs(tarjan)

开始判断：如果y点访问过了,
				则low [ x ] = min（low [ x ]，dfn[ y ]),
				y是目前可追溯到的最早结点。
				如果y没有访问过，那么继续遍历点y，
				并设low [ x ] = low[ y ]
				以便在后来的操作中找到了更早的追溯值来更新点x的low。



# 割点模板
如果一个点是根节点，有多个子树，它肯定是个割点。

如果一个点不是根节点：判断顶点U是否为割点，用U顶点的dnf值和它的所有的孩子顶点的low值进行比较，如果存在至少一个孩子顶点V满足low[v] >= dnf[u]，就说明顶点V访问顶点U的祖先顶点，必须通过顶点U，而不存在顶点V到顶点U祖先顶点的其它路径，所以顶点U就是一个割点。对于没有孩子顶点的顶点，显然不会是割点。

~~觉割点既然是无向图的，用什么前向星，直接上vector多好~~ 


```cpp
#include<cstdio>
#include<cstring>
#include<algorithm>
#include<vector>
using namespace std;
int const N=20005;
int n,m;
int in;
int dfn[N],low[N],cnt[N];
vector<int> G[N];
void init(){
    for(int i=0;i<=n;i++){
        dfn[i]=low[i]=cnt[i]=0;
        G[i].clear();
    }
    in=0;
}

void tarjan(int u,int root){
    dfn[u]=low[u]=++in;
    int child=0;

    for(int i=0;i<G[u].size();i++){
        int to=G[u][i];
        if(!dfn[to]){
            tarjan(to,root);
            low[u]=min(low[to],low[u]);

            if(u!=root&&low[to]>=dfn[u])cnt[u]=1;

            if(u==root)child++;
        }
        low[u]=min(low[u],dfn[to]);
    }
    if(u==root&&child>=2)cnt[root]=1;
}

int main(){
    init();
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        G[u].push_back(v);
        G[v].push_back(u);
    }

    for(int i=1;i<=n;i++){
        if(!dfn[i])tarjan(i,i);
    }
    int sum=0;
    for(int i=1;i<=n;i++){
        if(cnt[i])sum++;
    }
    printf("%d\n",sum);

    for(int i=1;i<=n;i++){
        if(cnt[i])
        printf("%d\n",i);
    }
    return 0;
}
