## bellman_ford算法
**虽然dijkstra很伄，但是他不能解决负权图**

### 核心算法

```c
for(k = 1; k <= n - 1; k++)
    for(i = 1; i <= m; i++)
        if(dis[v[i]] > dis[u[i]] + w[i])
            dis[v[i]] = dis[u[i]] + w[i];
```

主要是遍历点和边，判断u->v权值为w的边是否可以使距离变短

### 一些疑问

 - n-1次循环是因为两个点间，最多经历 n-1条边
 - 最短路径中不能出现环：如果有正环，去掉更小；如果负环，那么没有最短路

### 代码

```c
#include<cstdio>
#include<cstring>
#include<iostream>
#include<algorithm>
using namespace std;
const int N=510,M=10010;
const int INF=1e9+7;
int n,m；
int dist[N],backup[N];
struct EDGE
{
	int u,v,w;
}edge[M];
void init(){
	fill(dist,dist+n+1,INF);
}
int bellman_ford(){
	//memcpy(backup,dist,sizeof(dist));
	for(int k=1;k<=n-1;k++){//通过修改k可以得到最长k的最短路
		memcpy(backup,dist,sizeof(dist));

		for(int j=1;j<=m;j++){//看看每条边能否松弛
		int a=edge[j].u,b=edge[j].v,w=edge[j].w;
			dist[b]=min(dist[b],backup[a]+w);
		}

		int check=0
		for(int i=1;i<=n;i++){
			if(dist[i]!=backup[i]){
				check=1;
				break;
			}
		}
		if(!check)break;//不能松弛了退出
	}

	int flag =0;
	for(int i=1;i<=m;i++){
		if(dist[edge[i].v]>dist[edge[i].u]+edge[i].w){
			flag=1;//负权回路
			break;
		}
	}

	return flag;//1为有负权回路
}
int main(){
	cin>>n>>m;
	for(int i=1;i<=m;i++){
		int a,b,w;
		cin>>a>>b>>w;
		edge[i]={a,b,w};
	}
	init();
	int k=bellman_ford();
	return 0;
}
```
### 用处

 1. 在路长限制下求最短路
 2. 有负权回路情况下求最短路
 3. 判断负环
 4. ......



## spfa
spfa算是bellman_ford 的升级版，但是在特殊情况下复杂度会达到bellman_ford的情况，所以尽量用dijkstra

```c
#include<cstdio>
#include<cstring>
#include<algorithm>
#include<iostream>
#include<queue>
using namespace std;
int const MAXN=1e4+10;
int const MAXM=5*1e5+10;
int const INF = 1e9+7;
bool st[MAXN];
int dist[MAXN],head[MAXN];
struct EDGE
{
	int to,w,next;
}edge[MAXM];
int tot;
int n,m,s;
void init(){
	tot=1;
	fill(dist,dist+n+1,INF);
	fill(head,head+MAXN,-1);

	fill(st,st+n+1,false);
}
void add(int u,int v,int w){
	//if(tot==6)cout<<u<<" "<<v<<" "<<w<<endl;
	edge[tot].to=v;
	edge[tot].w=w;
	edge[tot].next=head[u];
	head[u]=tot++;
}
void spfa(int s){

	dist[s]=0;

	queue<int>q;
	q.push(s);
	st[s]=true;
	while(q.size()){
		//cout<<q.size()<<endl;
		int t=q.front();
		q.pop();
		st[t]=false;

		for(int i=head[t];i!=-1;i=edge[i].next){

			int j=edge[i].to;
			if(dist[j]>dist[t]+edge[i].w){
				dist[j]=dist[t]+edge[i].w;
				if(!st[j]){
					q.push(j);
					st[j]=true;
				}
			}
		}
	}

}
```
代码上看只是bellman_ford的队列优化版..


**spfa也可以用来判断负环（废话），用cnt数组保存每个点到1的距离（边数），所以当cnt[i]>=n说明有负环**

