### 求负环（vector）

```cpp
#include<cstring>
#include<cstdio>
#include<vector>
#include<queue>
#include<iostream>
#include<algorithm>
using namespace std;
const int INF = 0x3f3f3f3f;
int const N = 2*1e3+10;
typedef pair<int,int> pii;

vector<pii>graph[N];

int dis[N],cnt[N];
bool in[N];
int n,m;

void init(){
	memset(dis,INF,sizeof(dis));
	memset(in,false,sizeof in);
	memset(cnt,0,sizeof cnt);
}

bool spfa(int s){
	queue<int> q;
	init();
	q.push(s);
	dis[s]=0;
	in[s]=true;
	cnt[s]=1;

	while(!q.empty()){
		int x=q.front();
		q.pop();
		in[x]=false;

		for(unsigned int i=0;i<graph[x].size();i++){
			int y=graph[x][i].first;
			int z=graph[x][i].second;

			if(dis[y]>dis[x]+z){
				dis[y]=dis[x]+z;
				if(!in[y]){
					cnt[y]=cnt[x]+1;
					q.push(y);
					in[y]=true;
					if(cnt[y]>=n){
						return true;
					}
				}
			}
		}
	}

	return false;
}

int main(){
	int T;
	scanf("%d",&T);
	while(T--){
		scanf("%d%d",&n,&m);
		for(int i=1;i<=n;i++){
			graph[i].clear();
		}

		for(int i=1;i<=m;i++){
			int u,v,w;
			scanf("%d%d%d",&u,&v,&w);
			graph[u].push_back(make_pair(v,w));
			if(w>=0)graph[v].push_back(make_pair(u,w));
		}
		bool f;
		f=spfa(1);
		if(f)puts("YES");
		else puts("NO");
	}
	return 0;
}
