### 最短路计数问题

```c
#include<cstring>
#include<algorithm>
#include<queue>
using namespace std;
//typedef pair<int,int> PII;//距离 编号
int const MOD = 100003;
int const MAXN=1000000+10;
int const MAXM=2000000+10;
int const INF =1e9+7;
struct EDGE
{
	int to,next;
}edge[MAXM];
int tot=0;
int head[MAXN];
int dis[MAXN];
int st[MAXN];
int n,m;
int sum[MAXN];
void init(){
	tot=0;
	fill(head,head+n+1,-1);
	fill(st,st+n+1,false);
	fill(dis,dis+n+1,INF);
	memset(sum,0,sizeof(sum));
}

void add_edge(int u,int v){
	edge[++tot].to=v;
	//edge[tot].w=w;
	edge[tot].next=head[u];
	head[u]=tot;
}

void dijkstra(int s){
queue<int> q;	
st[s]=1;
dis[s]=0;
sum[s]=1;
q.push(s);
while(q.size()){
	int x=q.front();
	q.pop();
	st[x]=0;
	for(int i=head[x];i!=-1;i=edge[i].next){
		int y=edge[i].to;
		if(dis[y]>dis[x]+1){
			dis[y]=dis[x]+1;
			sum[y]=sum[x];
			if(!st[y]){
				q.push(y);
				dis[y]=1;
			}
		}
		else if(dis[y]==dis[x]+1){
			sum[y]+=sum[x];
			sum[y]%=MOD;
		}
	}
}
}
```
这是无权图(有权也不影响)

用了一个sum来保存最短路数，如果最短路更新那么sum[y]=sum[x]

如果不能更新但也是最短路，说明重边sum[y]+=sum[x]

